const data = $input.first().json;
const slides = data.slides ?? [];
const cliente = data.cliente ?? 'Cliente';
const fecha = data.fecha ?? new Date().toISOString().slice(0,10);
const siteUrl = data.url ?? '';

function stripMd(text) {
  return text
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .replace(/`(.*?)`/g, '$1')
    .replace(/^\|(.+)\|$/gm, (m, content) => {
      const cells = content.split('|').map(c => c.trim()).filter(c => c && !c.match(/^[-:\s]+$/));
      return cells.length ? cells.join('  |  ') : '';
    })
    .replace(/^[-:\s|]+$/gm, '')
    .replace(/---+/gm, '')
    .replace(/^\s*[-*+]\s+/gm, '• ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const sectionsHtml = slides.map((slide, i) => {
  const title = slide.match(/^# (.+)/m)?.[1] ?? `Sección ${i+1}`;
  const body = slide.replace(/^# .+/m, '').trim();
  const htmlBody = body
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/## (.+)/g, '<h3 style="color:#444;margin:12px 0 4px">$1</h3>')
    .replace(/\|[^\n]+\|/gm, (m) => {
      const cells = m.split('|').filter(c => c.trim() && !c.match(/^[-:\s]+$/));
      return '<span style="font-family:monospace;font-size:12px">' + cells.map(c => c.trim()).join(' │ ') + '</span>';
    })
    .replace(/^\s*[-*+]\s+(.+)/gm, '<li>$1</li>')
    .replace(/\n/g, '<br>');
  return `<div style="margin-bottom:28px">
    <h2 style="color:#1a73e8;border-bottom:2px solid #e8f0fe;padding-bottom:8px;margin-bottom:12px">${title}</h2>
    <div style="line-height:1.6">${htmlBody}</div>
  </div>`;
}).join('\n');

const slidesRequests = [];
slides.forEach((slide, index) => {
  const slideId = `slide_${index}`;
  const titleId = `titlebox_${index}`;
  const bodyId  = `bodybox_${index}`;
  const title   = slide.match(/^# (.+)/m)?.[1] ?? `Sección ${index+1}`;
  const body    = stripMd(slide.replace(/^# .+\n?/m, '')).slice(0, 3000);
  slidesRequests.push({ createSlide: { objectId: slideId, insertionIndex: index, slideLayoutReference: { predefinedLayout: 'BLANK' } } });
  slidesRequests.push({ createShape: { objectId: titleId, shapeType: 'TEXT_BOX', elementProperties: { pageObjectId: slideId, size: { width: { magnitude: 580, unit: 'PT' }, height: { magnitude: 50, unit: 'PT' } }, transform: { scaleX: 1, scaleY: 1, translateX: 30, translateY: 20, unit: 'PT' } } } });
  slidesRequests.push({ insertText: { objectId: titleId, insertionIndex: 0, text: title } });
  slidesRequests.push({ updateTextStyle: { objectId: titleId, style: { bold: true, fontSize: { magnitude: 22, unit: 'PT' }, foregroundColor: { opaqueColor: { rgbColor: { red: 0.1, green: 0.45, blue: 0.93 } } } }, fields: 'bold,fontSize,foregroundColor' } });
  const bodyText = body || '(sin datos disponibles)';
  slidesRequests.push({ createShape: { objectId: bodyId, shapeType: 'TEXT_BOX', elementProperties: { pageObjectId: slideId, size: { width: { magnitude: 580, unit: 'PT' }, height: { magnitude: 290, unit: 'PT' } }, transform: { scaleX: 1, scaleY: 1, translateX: 30, translateY: 80, unit: 'PT' } } } });
  slidesRequests.push({ insertText: { objectId: bodyId, insertionIndex: 0, text: bodyText } });
  slidesRequests.push({ updateTextStyle: { objectId: bodyId, style: { fontSize: { magnitude: 11, unit: 'PT' } }, fields: 'fontSize' } });
});

return [{ json: { ...data, sectionsHtml, emailSubject: `Informe SEO — ${cliente} — ${fecha}`, slidesRequests } }];

const auditData = $('Code — Preparar datos').first().json;
const presId    = $('Google Slides — Crear presentación').first().json.presentationId;
const presUrl   = `https://docs.google.com/presentation/d/${presId}/edit`;
const cliente   = auditData.cliente;
const fecha     = auditData.fecha;
const siteUrl   = auditData.url;

const slidesButton = `
<div style="text-align:center;margin:0 0 32px">
  <a href="${presUrl}"
     style="display:inline-block;background:#1a73e8;color:white;text-decoration:none;
            padding:14px 32px;border-radius:8px;font-size:16px;font-weight:bold;
            box-shadow:0 2px 8px rgba(26,115,232,0.4)">
    📊 Ver presentación en Google Slides
  </a>
  <p style="color:#666;font-size:13px;margin-top:10px">${presUrl}</p>
</div>`;

const emailHtml = `<!DOCTYPE html>
<html><body style="font-family:Arial,sans-serif;max-width:820px;margin:0 auto;padding:24px;color:#333">
  <div style="background:linear-gradient(135deg,#1a73e8,#0d47a1);color:white;padding:24px;border-radius:10px;margin-bottom:28px">
    <h1 style="margin:0;font-size:24px">Informe SEO — ${cliente}</h1>
    <p style="margin:8px 0 0;opacity:0.9">🌐 ${siteUrl} &nbsp;|&nbsp; 📅 ${fecha}</p>
  </div>
  ${slidesButton}
  ${auditData.sectionsHtml}
  <p style="color:#aaa;font-size:11px;margin-top:36px;border-top:1px solid #eee;padding-top:12px">
    Generado automáticamente por audit-seo
  </p>
</body></html>`;

const emailSubject = `${auditData.emailSubject} | 📊 docs.google.com/presentation/d/${presId}`;

return [{ json: { ...auditData, emailHtml, emailSubject, presId, presUrl } }];

const data  = $('Code — Email con link de slides').first().json;
return [{
  json: {
    ok: true,
    cliente:          data.cliente,
    fecha:            data.fecha,
    total_slides:     data.total_slides,
    gmail_enviado:    true,
    presentacion_id:  data.presId,
    presentacion_url: data.presUrl,
    carpeta_drive:    `CL-INFORMES / ${data.cliente} - ${data.fecha}`,
  }
}];
